import{_ as i,o as s,c as t,an as e}from"./chunks/framework.BmuutBn3.js";const c=JSON.parse('{"title":"Loading a Domain","description":"","frontmatter":{},"headers":[],"relativePath":"usage/loading_a_domain.md","filePath":"usage/loading_a_domain.md","lastUpdated":null}'),n={name:"usage/loading_a_domain.md"};function o(h,a,d,l,p,r){return s(),t("div",null,[...a[0]||(a[0]=[e('<h1 id="Loading-a-Domain" tabindex="-1">Loading a Domain <a class="header-anchor" href="#Loading-a-Domain" aria-label="Permalink to &quot;Loading a Domain {#Loading-a-Domain}&quot;">​</a></h1><p>ADRIA is designed to work with <code>Domain</code> data packages.</p><p>At their core, data packages are a directory containing a <code>datapackage.json</code> file, following the <a href="https://specs.frictionlessdata.io/data-package/" target="_blank" rel="noreferrer">spec</a> as outlined by Frictionless Data. In short, these are pre-packaged data sets that hold all the necessary data to run simulations for a given spatial domain.</p><p>See <a href="/ADRIA.jl/dev/architecture/architecture#Architectural-overview">Architectural overview</a> for more information.</p><p>A <code>Domain</code> may be loaded by calling the <code>load_domain</code> function with the path to the data package. Note that the data package is the <em>directory</em>.</p><p>By convention we assign the <code>Domain</code> to <code>dom</code>, although this variable can be named anything.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dom </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ADRIA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">load_domain</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;path to domain data package&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;&lt;RCP&gt;&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>ReefMod Engine datasets can also be used to run ADRIAmod simulations for the Great Barrier Reef.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dom </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ADRIA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">load_domain</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(RMEDomain, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;path to ReefModEngine dataset&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;45&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>Note that at the moment the target RCP has to be specified.</p><p>ReefMod Matlab datasets that have been converted to NetCDF files can also be used to run ADRIAmod simulation for the Great Barrier Reef.</p><div class="language-julia vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">julia</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dom </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> ADRIA</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">load_domain</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(ReefModDomain, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;path to ReefMod dataset&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;45&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>The target RCP must also be specified.</p>',13)])])}const g=i(n,[["render",o]]);export{c as __pageData,g as default};
